CREATE TABLE students (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    age INTEGER,
    grade REAL
);

INSERT INTO students (name, age, grade) VALUES
    ('Ahmet Yilmaz', 20, 85.50),
    ('Ayse Kaya', 21, 92.00),
    ('Mehmet Demir', 22, 67.25),
    ('Zeynep Sahin', 20, 78.75),
    ('Can Ozturk', 23, 55.00);

-- Once mevcut durumu goster
SELECT * FROM students;

-- Tek kaydi guncelleme
UPDATE students
SET grade = 70.00
WHERE name = 'Mehmet Demir';

-- Birden fazla kolon guncelleme
UPDATE students
SET grade = grade + 5, age = age + 1
WHERE name = 'Can Ozturk';

-- Kosula uyan tum kayitlari guncelleme
UPDATE students
SET grade = grade * 1.05
WHERE grade < 60;

-- Guncelleme sonrasi durumu goster
SELECT * FROM students;

-- Tek kaydi silme
DELETE FROM students
WHERE name = 'Can Ozturk';

-- Kosula uyan tum kayitlari silme
DELETE FROM students
WHERE grade < 50;

-- Son durumu goster
SELECT * FROM students;
